#include <bits/stdc++.h>
using namespace std;
bool s[10][10],h[10][10],l[10][10],g[10][10];
int a[10][10],w[10][10];
bool flag=false;
void dfs(int x,int y){
	if(flag)
		return;
	if(x>9){
		flag=true;
		//printf("\n");
		for(int i=1;i<=9;i++){
			for(int j=1;j<=9;j++)
				printf("%d ",a[i][j]);
			printf("\n");
		}
		return;
	}
	if(s[x][y])
		dfs(x+(y==9),y%9+1);
	else
		for(int i=1;i<=9;i++)
			if(!h[x][i] && !l[y][i] && !g[w[x][y]][i]){
				h[x][i]=l[y][i]=g[w[x][y]][i]=true,a[x][y]=i;
				dfs(x+(y==9),y%9+1);
				h[x][i]=l[y][i]=g[w[x][y]][i]=false;
				if(flag)
					return;
			}
}
int main(){
	for(int i=1;i<=9;i++)
		for(int j=1;j<=9;j++){
			scanf("%d",&a[i][j]);
			w[i][j]=(i-1)/3*3+j/3+(j%3>0);
			if(a[i][j]>0)
				s[i][j]=h[i][a[i][j]]=l[j][a[i][j]]=g[w[i][j]][a[i][j]]=true;
		}
	dfs(1,1);
	return 0;
}
